mapper.select:
SELECT qs.id
FROM quiz_sets qs
WHERE qs.challenge_date = #{challengeDate}
  AND qs.status = 'PUBLISHED'
  AND NOT EXISTS (
      SELECT 1 FROM user_quiz_assignments previous
      WHERE previous.user_id = #{userId}
        AND previous.quiz_set_id = qs.id
  )
ORDER BY qs.variant_code, qs.id
